visited = []

def has_cycle(node):
    if node in visiting:
        return True
    if node in visited:
        return False
    visiting.append(node)
    for neighbor in graph[node]:
        if has_cycle(neighbor):
            return True
    visiting.pop()
    visited.append(node)
    return False

